package handlers

import (
	"encoding/json"
	"errors"
	"io"
	"log/slog"
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"

	"github.com/alexmorbo/seasonfill/application/runtimeconfig"
	"github.com/alexmorbo/seasonfill/interface/http/dto"
)

const runtimeConfigBodyLimit = 64 << 10

// RuntimeConfigHandler is the GET/PUT handler for
// /api/v1/config/runtime. AutoGeneratedAPIKey is read-only — any value
// the client sends on PUT is silently dropped (the usecase does not
// read it).
type RuntimeConfigHandler struct {
	uc     *runtimeconfig.UseCase
	logger *slog.Logger
}

func NewRuntimeConfigHandler(uc *runtimeconfig.UseCase, logger *slog.Logger) *RuntimeConfigHandler {
	if logger == nil {
		logger = slog.Default()
	}
	return &RuntimeConfigHandler{uc: uc, logger: logger}
}

// Get returns the current runtime_config row. Swagger annotations
// added in the make-openapi follow-up commit (deferred per AC8).
func (h *RuntimeConfigHandler) Get(c *gin.Context) {
	body, ts, err := h.uc.Get(c.Request.Context())
	if err != nil {
		h.writeError(c, err)
		return
	}
	if !ts.IsZero() {
		c.Header("Last-Modified", ts.UTC().Format(http.TimeFormat))
	}
	c.JSON(http.StatusOK, body)
}

// Update full-replaces the runtime_config row.
func (h *RuntimeConfigHandler) Update(c *gin.Context) {
	var in dto.RuntimeConfigDTO
	if !readRuntimeConfigBody(c, &in) {
		return
	}
	var iusPtr *time.Time
	if raw := c.GetHeader("If-Unmodified-Since"); raw != "" {
		t, err := http.ParseTime(raw)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
				Error: "If-Unmodified-Since: " + err.Error(),
				Code:  "BAD_REQUEST",
			})
			return
		}
		iusPtr = &t
	}
	body, ts, err := h.uc.Update(c.Request.Context(), in, iusPtr)
	if err != nil {
		h.writeError(c, err)
		return
	}
	if !ts.IsZero() {
		c.Header("Last-Modified", ts.UTC().Format(http.TimeFormat))
	}
	c.JSON(http.StatusOK, body)
}

func (h *RuntimeConfigHandler) writeError(c *gin.Context, err error) {
	var verr *runtimeconfig.ValidationError
	switch {
	case errors.As(err, &verr):
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: verr.Error(), Code: verr.Code,
		})
	case errors.Is(err, runtimeconfig.ErrStaleWrite):
		c.AbortWithStatusJSON(http.StatusPreconditionFailed, dto.ErrorResponse{
			Error: "runtime_config was modified by another client",
			Code:  "STALE_WRITE",
		})
	default:
		h.logger.ErrorContext(c.Request.Context(), "runtimeconfig.handler.error",
			slog.String("error", err.Error()))
		c.AbortWithStatusJSON(http.StatusInternalServerError, dto.ErrorResponse{
			Error: "internal server error",
		})
	}
}

func readRuntimeConfigBody(c *gin.Context, out *dto.RuntimeConfigDTO) bool {
	ct := c.GetHeader("Content-Type")
	if !strings.HasPrefix(ct, "application/json") {
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: "content-type must be application/json", Code: "BAD_REQUEST",
		})
		return false
	}
	c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, runtimeConfigBodyLimit)
	raw, err := io.ReadAll(c.Request.Body)
	if err != nil {
		var maxErr *http.MaxBytesError
		if errors.As(err, &maxErr) {
			c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
				Error: "payload too large", Code: "BAD_REQUEST",
			})
			return false
		}
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: "cannot read body", Code: "BAD_REQUEST",
		})
		return false
	}
	if err := json.Unmarshal(raw, out); err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: "malformed body", Code: "BAD_REQUEST",
		})
		return false
	}
	return true
}
